exercises.solution:
import random

class CSIDHKeyExchange:
    def __init__(self, n_primes: int = 5, max_exp: int = 5):
        self.primes = [3, 5, 7, 11, 13][:n_primes]
        self.max_exp = max_exp
        self.j0 = 1728

    def _action(self, j: int, exps: list) -> int:
        for i, e in enumerate(exps):
            j = (j + self.primes[i] * e * 137) % 100000
        return j

    def keygen(self) -> tuple:
        secret = [random.randint(-self.max_exp, self.max_exp) for _ in self.primes]
        public = self._action(self.j0, secret)
        return (secret, public)

    def exchange(self, my_secret: list, their_public: int) -> int:
        return self._action(their_public, my_secret)
